const crypto = require('crypto');
function verify(item, secret, tol = 300) {
  const h = item.headers ?? {};
  const ts = parseInt(h['x-managecall-timestamp'] ?? '0', 10);
  if (Math.abs(Date.now() / 1000 - ts) > tol) throw new Error('timestamp_expired');
  const body = typeof item.body === 'string' ? item.body : JSON.stringify(item.body ?? {});
  const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(`${ts}.${body}`).digest('hex');
  if (!crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(h['x-managecall-signature-256'] ?? ''))) throw new Error('invalid_signature');
}
verify($input.first(), $env.MANAGECALL_WEBHOOK_SECRET);
return $input.all();

const payload = $input.first().json.body ?? {};
const data = payload.data ?? {};

// Anomaly: call completed in under 5 seconds with a hangup disposition.
// Adjust thresholds to match operational norms.
const SHORT_CALL_THRESHOLD_SECONDS = parseInt($env.ANOMALY_SHORT_CALL_SECONDS ?? '5', 10);
const isShort = (data.duration_seconds ?? 999) < SHORT_CALL_THRESHOLD_SECONDS;
const isHangup = String(data.disposition ?? '').toLowerCase().includes('hangup');
const isAnomaly = isShort && isHangup;

return [{
  json: {
    is_anomaly: isAnomaly,
    call_id: data.call_id,
    direction: data.direction,
    from_number: data.from_number,
    to_number: data.to_number,
    duration_seconds: data.duration_seconds,
    disposition: data.disposition,
    tenant_id: payload.tenant_id,
    occurred_at: payload.timestamp,
  }
}];
